INSERT INTO _meta_kpi (kpi_name, kpi_name_vi, formula_sql, description_vi, related_tables, related_questions) VALUES
('gross_margin_pct', 'Biên lợi nhuận gộp', '(revenue_recognized - cogs) / revenue_recognized * 100', 'Biên lợi nhuận gộp (%) — tỷ lệ lợi nhuận gộp trên doanh thu. Theo dõi theo dự án, theo mảng (thi công/BĐS), theo loại công trình.', 'project_financials, projects', 'Q3'),
('cost_variance', 'Chênh lệch chi phí', 'actual_cost_to_date - planned_budget', 'Chênh lệch chi phí so dự toán (triệu VND). Dương = vượt chi phí. Phân tích theo hạng mục qua bảng cost_items.', 'projects, cost_items', 'Q2'),
('cost_variance_pct', 'Tỷ lệ vượt chi phí', '(actual_cost_to_date - planned_budget) / planned_budget * 100', 'Tỷ lệ vượt chi phí so dự toán (%). Ngưỡng cảnh báo: > 10%.', 'projects', 'Q2'),
('schedule_variance_days', 'Chênh lệch tiến độ', 'actual_progress_pct - planned_progress_pct', 'Chênh lệch tiến độ (% điểm). Âm = chậm tiến độ. Kết hợp planned_end - actual_end cho từng milestone.', 'projects, project_milestones', 'Q1'),
('absorption_rate', 'Tỷ lệ hấp thụ BĐS', 'sold_units / total_units * 100', 'Tỷ lệ sản phẩm BĐS đã bán so tổng sản phẩm (%). Đánh giá hiệu quả bán hàng dự án.', 'projects, real_estate_units', 'Q5'),
('sell_through_rate', 'Tốc độ bán BĐS', 'units_sold / units_available', 'Số sản phẩm bán được trong tháng / tổng sản phẩm còn lại. Đánh giá tốc độ hấp thụ.', 're_sales_monthly', 'Q5'),
('inventory_holding_cost', 'Chi phí vốn tồn kho BĐS', 'unsold_value * interest_rate / 100 * holding_months / 12', 'Chi phí lãi vay phát sinh do tồn kho BĐS chưa bán (triệu VND). Tính theo giá trị tồn × lãi suất × thời gian.', 'real_estate_units, project_financing', 'Q5'),
('net_cash_flow', 'Dòng tiền thuần', 'total_inflow - total_outflow', 'Dòng tiền thuần hàng tháng (triệu VND). Âm = thiếu hụt. Cần theo dõi liên tục.', 'cash_flow_actual', 'Q4'),
('revenue_by_segment', 'Doanh thu theo mảng', 'SUM(revenue_recognized) GROUP BY project_type', 'Tổng doanh thu phân theo mảng thi công và BĐS. So sánh đóng góp.', 'project_financials, projects', 'Q1,Q3'),
('bid_ratio', 'Tỷ lệ giá thầu', 'bid_price / estimated_value', 'Tỷ lệ giá dự thầu so giá gói thầu. < 0.90 = rất cạnh tranh, rủi ro margin thấp.', 'bid_history', 'Q3'),
('bid_win_rate', 'Tỷ lệ trúng thầu', 'COUNT(result=trung_thau) / COUNT(*) * 100', 'Tỷ lệ trúng thầu (%). Theo dõi theo loại công trình.', 'bid_history', 'Q3'),
('receivable_aging', 'Tuổi nợ phải thu', 'DATEDIFF(CURRENT_DATE, due_date)', 'Số ngày quá hạn thanh toán. > 30 ngày cần theo dõi sát.', 'receivables', 'Q4'),
('project_rag_status', 'Trạng thái RAG dự án', 'CASE WHEN progress_gap < -15 OR cost_variance_pct > 10 THEN ''RED'' WHEN progress_gap < -5 OR cost_variance_pct > 5 THEN ''YELLOW'' ELSE ''GREEN'' END', 'Đánh giá tổng quan dự án: RED (có vấn đề nghiêm trọng), YELLOW (cần theo dõi), GREEN (bình thường).', 'projects', 'Q1'),
('avg_inventory_months', 'Thời gian tồn kho trung bình', 'AVG(DATEDIFF(CURRENT_DATE, listing_date) / 30) WHERE status=''chua_ban''', 'Thời gian tồn kho trung bình của sản phẩm BĐS chưa bán (tháng). > 12 tháng cần ưu tiên giải phóng.', 'real_estate_units', 'Q5');
INSERT INTO _meta_glossary (term_vi, term_en, definition_vi, domain) VALUES
('Chủ đầu tư', 'Project Owner / Client', 'Tổ chức, cá nhân sở hữu vốn đầu tư, thuê nhà thầu thi công', 'xay_dung'),
('Nhà thầu chính', 'Main Contractor', 'Đơn vị ký hợp đồng trực tiếp với chủ đầu tư để thi công toàn bộ/phần lớn công trình', 'xay_dung'),
('Nhà thầu phụ (NTP)', 'Subcontractor', 'Đơn vị được nhà thầu chính thuê thi công một phần công việc chuyên môn', 'xay_dung'),
('Dự toán', 'Cost Estimate', 'Tổng chi phí dự kiến cho dự án, được lập trước khi thi công', 'xay_dung'),
('Nghiệm thu', 'Acceptance / Inspection', 'Kiểm tra và xác nhận khối lượng, chất lượng công việc hoàn thành', 'xay_dung'),
('Giải ngân', 'Disbursement', 'Việc chuyển tiền từ nguồn vốn (ngân sách/vay) cho dự án theo tiến độ', 'xay_dung'),
('Đấu thầu', 'Bidding / Tendering', 'Quy trình cạnh tranh để chọn nhà thầu thi công dựa trên hồ sơ dự thầu', 'xay_dung'),
('Gói thầu', 'Bid Package', 'Phần công việc được tách ra để đấu thầu, có giá dự toán riêng', 'xay_dung'),
('Giá trúng thầu', 'Winning Bid Price', 'Giá mà nhà thầu đề xuất và được chấp thuận', 'xay_dung'),
('Bid ratio', 'Bid Ratio', 'Tỷ lệ giá dự thầu / giá gói thầu. Thấp hơn = cạnh tranh hơn nhưng rủi ro margin', 'xay_dung'),
('BOT', 'Build-Operate-Transfer', 'Hình thức đầu tư: xây dựng, vận hành thu phí, sau đó chuyển giao cho nhà nước', 'xay_dung'),
('BVTC', 'Bản vẽ thi công', 'Bản vẽ chi tiết kỹ thuật dùng để thi công tại công trường', 'xay_dung'),
('M&E', 'Mechanical & Electrical', 'Hệ thống cơ điện trong công trình: điện, nước, HVAC, PCCC', 'xay_dung'),
('Đất yếu', 'Soft Ground', 'Nền đất có sức chịu tải kém, cần gia cố (cọc, vải địa kỹ thuật) trước khi xây', 'xay_dung'),
('Rọ đá', 'Gabion', 'Lưới thép chứa đá, dùng trong kè chống sạt lở bờ sông', 'xay_dung'),
('Kè', 'Revetment / Embankment', 'Công trình bảo vệ bờ sông, bờ biển khỏi xói lở', 'xay_dung'),
('Shophouse', 'Shophouse', 'Nhà phố thương mại, tầng trệt kinh doanh, tầng trên để ở', 'bat_dong_san'),
('Nhà liền kề', 'Townhouse', 'Nhà thiết kế đồng bộ trong khu đô thị, chung tường với nhà bên cạnh', 'bat_dong_san'),
('Đất nền', 'Land Plot', 'Lô đất đã có hạ tầng (đường, điện, nước), khách tự xây', 'bat_dong_san'),
('Khu đô thị (KĐT)', 'Urban Area', 'Khu vực quy hoạch đồng bộ: nhà ở, đường, công viên, trường học', 'bat_dong_san'),
('KDC', 'Khu dân cư', 'Khu dân cư — vùng quy hoạch cho mục đích ở, thường quy mô nhỏ hơn KĐT', 'bat_dong_san'),
('KCN', 'Khu công nghiệp', 'Khu vực chuyên dụng cho sản xuất công nghiệp, có hạ tầng riêng', 'bat_dong_san'),
('Tỷ lệ hấp thụ', 'Absorption Rate', 'Tỷ lệ sản phẩm BĐS đã bán trên tổng sản phẩm mở bán (%)', 'bat_dong_san'),
('Tốc độ bán', 'Sell-through Rate', 'Số sản phẩm bán được mỗi tháng — đo thanh khoản dự án', 'bat_dong_san'),
('Tồn kho BĐS', 'RE Inventory', 'Sản phẩm BĐS chưa bán được — gánh chi phí vốn (lãi vay)', 'bat_dong_san'),
('Mở bán', 'Sales Launch', 'Thời điểm chính thức giới thiệu và bán sản phẩm BĐS ra thị trường', 'bat_dong_san'),
('Đặt cọc', 'Deposit / Reservation', 'Khách đặt tiền giữ chỗ trước khi ký hợp đồng mua bán chính thức', 'bat_dong_san'),
